#include <bits/stdc++.h>
using namespace std;

int main(){
    int x;
    bool xz1,xz2;
    cin>>x;
    xz1 = x%2==0;
    xz2 = 4<x&&x<=12;
    cout << (xz1&&xz2) <<" ";
    cout <<(xz1||xz2)<<" ";
    cout <<((xz1&&!xz2)||(xz2&&!xz1))<<" ";
    cout <<(!xz1&&!xz2)<<" ";
    return 0;
}
